python3 << 'EOF'
import tempfile
import pathlib
import contextlib
import adblock

class DeserializationError(Exception):
    pass

@contextlib.contextmanager
def _map_exceptions():
    adblock_deserialization_error = getattr(adblock, "DeserializationError", ValueError)
    try:
        yield
    except adblock_deserialization_error as e:
        if isinstance(e, ValueError) and str(e) != "DeserializationError":
            raise
        raise DeserializationError(str(e))

# Test: OSError is NOT caught by _map_exceptions
with tempfile.TemporaryDirectory() as tmpdir:
    cache_path = pathlib.Path(tmpdir) / "adblock-cache.dat"
    cache_path.mkdir()

    engine = adblock.Engine(adblock.FilterSet())

    try:
        with _map_exceptions():
            engine.deserialize_from_file(str(cache_path))
        print("ERROR: OSError was NOT raised! This would mean the bug is fixed.")
    except OSError as e:
        print(f"CORRECT: OSError escaped from _map_exceptions: {e}")
    except DeserializationError as e:
        print(f"ERROR: OSError was converted to DeserializationError (bug is fixed)")
    except Exception as e:
        print(f"ERROR: Got unexpected exception: {type(e).__name__}: {e}")
EOF

